import { useCallback, useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence, useAnimation, PanInfo } from 'framer-motion';
import { SidebarHeader } from './SidebarHeader';
import { SidebarNavigation } from './SidebarNavigation';
import { SidebarUserSection } from './SidebarUserSection';
import { useSidebar } from './useSidebar';
import { User } from '../../types';

interface SidebarProps {
  readonly user: User | null;
  readonly onLogout: () => void;
}

export const Sidebar = ({ user, onLogout }: SidebarProps) => {
  const { isOpen, isMobile, closeSidebar } = useSidebar();
  const controls = useAnimation();
  const [dragProgress, setDragProgress] = useState(0);
  const sidebarRef = useRef<HTMLDivElement>(null);

  const sidebarWidth = 256;
  const dragThreshold = sidebarWidth * 0.4;

  useEffect(() => {
    if (isOpen) {
      controls.start({ x: 0, transition: { type: 'spring', stiffness: 300, damping: 30 } });
      setDragProgress(0);
    }
  }, [isOpen, controls]);

  const handleDrag = useCallback(
    (_event: MouseEvent | TouchEvent | PointerEvent, info: PanInfo) => {
      if (!isMobile || !isOpen) return;

      const dragX = Math.max(0, -info.offset.x);
      const progress = Math.min(dragX / dragThreshold, 1);
      setDragProgress(progress);
    },
    [isMobile, isOpen, dragThreshold],
  );

  const handleDragEnd = useCallback(
    (_event: MouseEvent | TouchEvent | PointerEvent, info: PanInfo) => {
      if (!isMobile || !isOpen) return;

      const dragX = -info.offset.x;
      const velocity = -info.velocity.x;

      if (dragX > dragThreshold || velocity > 500) {
        closeSidebar();
        controls.start({
          x: -sidebarWidth,
          transition: { type: 'spring', stiffness: 300, damping: 30 },
        });
      } else {
        controls.start({ x: 0, transition: { type: 'spring', stiffness: 300, damping: 30 } });
        setDragProgress(0);
      }
    },
    [isMobile, isOpen, closeSidebar, controls, sidebarWidth, dragThreshold],
  );

  const sidebarContent = (
    <aside className="flex h-full w-64 flex-col bg-slate-900">
      <SidebarHeader />
      <SidebarNavigation onItemClick={isMobile ? closeSidebar : undefined} />
      <SidebarUserSection user={user} onLogout={onLogout} />
    </aside>
  );

  if (!isMobile) {
    return sidebarContent;
  }

  const backdropOpacity = isOpen ? 0.5 * (1 - dragProgress * 0.8) : 0;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div
            className="fixed inset-0 z-40 bg-black"
            initial={{ opacity: 0 }}
            animate={{ opacity: backdropOpacity }}
            exit={{ opacity: 0 }}
            onClick={closeSidebar}
            aria-hidden="true"
          />
          <motion.div
            ref={sidebarRef}
            className="fixed inset-y-0 left-0 z-50 touch-pan-y"
            initial={{ x: -sidebarWidth }}
            animate={controls}
            exit={{ x: -sidebarWidth, transition: { type: 'spring', stiffness: 300, damping: 30 } }}
            drag={isMobile ? 'x' : false}
            dragConstraints={{ left: -sidebarWidth, right: 0 }}
            dragElastic={0}
            onDrag={handleDrag}
            onDragEnd={handleDragEnd}
          >
            {sidebarContent}
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

</result>
