import { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { AppDispatch, RootState } from '../store';
import { fetchBudgets } from '../store/budgetSlice';
import { fetchTransactions } from '../store/transactionSlice';
import { useSettings } from '../hooks/useSettings';
import { formatMoney } from '../lib/formatMoney';

export const DashboardPage = () => {
  const dispatch = useDispatch<AppDispatch>();
  const { budgets, loading: budgetsLoading } = useSelector((state: RootState) => state.budgets);
  const { transactions, loading: transactionsLoading } = useSelector(
    (state: RootState) => state.transactions,
  );
  const { settings } = useSettings();

  useEffect(() => {
    dispatch(fetchBudgets());
    dispatch(fetchTransactions({ limit: 5 }));
  }, [dispatch]);

  const totalBudget = budgets.reduce((sum, b) => sum + b.amount, 0);
  const totalSpent = budgets.reduce((sum, b) => sum + b.spent, 0);
  const remaining = totalBudget - totalSpent;

  const isLoading = budgetsLoading || transactionsLoading;

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-emerald-500 border-t-transparent"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Overview</h2>

      <div className="grid gap-4 md:grid-cols-3">
        <div className="rounded-lg bg-white p-6 shadow">
          <h3 className="text-sm font-medium text-gray-500">Total Budget</h3>
          <p className="mt-2 text-3xl font-semibold text-gray-900">
            {formatMoney(totalBudget, settings?.currency)}
          </p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow">
          <h3 className="text-sm font-medium text-gray-500">Total Spent</h3>
          <p className="mt-2 text-3xl font-semibold text-red-600">
            {formatMoney(totalSpent, settings?.currency)}
          </p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow">
          <h3 className="text-sm font-medium text-gray-500">Remaining</h3>
          <p
            className={`mt-2 text-3xl font-semibold ${remaining >= 0 ? 'text-emerald-600' : 'text-red-600'}`}
          >
            {formatMoney(remaining, settings?.currency)}
          </p>
        </div>
      </div>

      <div className="rounded-lg bg-white p-6 shadow">
        <h3 className="mb-4 text-lg font-semibold text-gray-900">Recent Transactions</h3>
        {transactions.length === 0 ? (
          <p className="text-gray-500">No recent transactions</p>
        ) : (
          <ul className="divide-y divide-gray-200">
            {transactions.map((transaction) => (
              <li key={transaction.id} className="flex items-center justify-between py-3">
                <div>
                  <p className="font-medium text-gray-900">{transaction.description}</p>
                  <p className="text-sm text-gray-500">
                    {new Date(transaction.date).toLocaleDateString()}
                  </p>
                </div>
                <span
                  className={`font-semibold ${transaction.type === 'EXPENSE' ? 'text-red-600' : 'text-emerald-600'}`}
                >
                  {transaction.type === 'EXPENSE' ? '-' : '+'}
                  {formatMoney(transaction.amount, settings?.currency)}
                </span>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

